var maxPerformance = function(n, speed, efficiency, k) {
    const MOD = BigInt(10**9 + 7);
    const engineers = efficiency.map((e, i) => [e, speed[i]]);
    engineers.sort((a, b) => b[0] - a[0]);
    // Min-heap via sorted array simulation for correctness (n<=1e5, acceptable)
    const heap = [];
    let speedSum = 0n;
    let best = 0n;
    for (const [eff, spd] of engineers) {
        heap.push(spd);
        heap.sort((a, b) => a - b);
        speedSum += BigInt(spd);
        if (heap.length > k) {
            speedSum -= BigInt(heap.shift());
        }
        const perf = speedSum * BigInt(eff);
        if (perf > best) best = perf;
    }
    return Number(best % MOD);
};
